import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  Box, 
  Button, 
  Card, 
  CardContent, 
  CircularProgress, 
  Container, 
  Grid, 
  Paper, 
  Typography,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Alert,
  Divider,
  Chip,
  IconButton,
  Tooltip,
  Fade,
  Skeleton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  List,
  ListItem,
  ListItemText,
  TextField,
  Tab,
  Tabs,
  Switch,
  FormControlLabel,
  Snackbar,
  Menu,
  MenuItem
} from '@mui/material';
import RefreshIcon from '@mui/icons-material/Refresh';
import DeleteIcon from '@mui/icons-material/Delete';
import DescriptionIcon from '@mui/icons-material/Description';
import PublicIcon from '@mui/icons-material/Public';
import BadgeIcon from '@mui/icons-material/Badge';
import PassportIcon from '@mui/icons-material/ArticleOutlined';
import DownloadIcon from '@mui/icons-material/Download';
import InfoIcon from '@mui/icons-material/Info';
import VisibilityIcon from '@mui/icons-material/Visibility';
import CloseIcon from '@mui/icons-material/Close';
import CalendarTodayIcon from '@mui/icons-material/CalendarToday';
import FingerprintIcon from '@mui/icons-material/Fingerprint';
import PersonIcon from '@mui/icons-material/Person';
import EditIcon from '@mui/icons-material/Edit';
import SaveIcon from '@mui/icons-material/Save';
import CancelIcon from '@mui/icons-material/Cancel';
import PrintIcon from '@mui/icons-material/Print';
import ImageIcon from '@mui/icons-material/Image';
import MoreVertIcon from '@mui/icons-material/MoreVert';
import FileDownloadIcon from '@mui/icons-material/FileDownload';
import ContentCopyIcon from '@mui/icons-material/ContentCopy';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title as ChartTitle,
  Tooltip as ChartTooltip,
  Legend,
  ArcElement
} from 'chart.js';
import { Bar, Pie } from 'react-chartjs-2';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  ChartTitle,
  ChartTooltip,
  Legend,
  ArcElement
);

const Dashboard = () => {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedScan, setSelectedScan] = useState(null);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [editedScan, setEditedScan] = useState(null);
  const [tabValue, setTabValue] = useState(0);
  const [snackbarOpen, setSnackbarOpen] = useState(false);
  const [snackbarMessage, setSnackbarMessage] = useState('');
  const [menuAnchorEl, setMenuAnchorEl] = useState(null);
  const menuOpen = Boolean(menuAnchorEl);

  const fetchStats = async () => {
    setLoading(true);
    try {
      const response = await axios.get('http://localhost:5001/api/stats');
      setStats(response.data);
      setError(null);
    } catch (err) {
      setError('Error fetching statistics: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const resetStats = async () => {
    setLoading(true);
    try {
      await axios.post('http://localhost:5001/api/reset-stats');
      fetchStats();
    } catch (err) {
      setError('Error resetting statistics: ' + err.message);
    }
  };

  const handleOpenScanDetails = (scan) => {
    setSelectedScan(scan);
    setDialogOpen(true);
    // Reset edit mode when opening dialog
    setEditMode(false);
    setEditedScan(null);
    setTabValue(0);
  };

  const handleCloseScanDetails = () => {
    setDialogOpen(false);
    // Keep the selected scan data for a smooth closing animation
    setTimeout(() => {
      setSelectedScan(null);
      setEditedScan(null);
      setEditMode(false);
    }, 300);
  };

  const handleTabChange = (event, newValue) => {
    setTabValue(newValue);
  };

  const handleEditClick = () => {
    setEditMode(true);
    // Create a deep copy of the selected scan for editing
    setEditedScan(JSON.parse(JSON.stringify(selectedScan)));
  };

  const handleCancelEdit = () => {
    setEditMode(false);
    setEditedScan(null);
  };

  const handleSaveEdit = async () => {
    try {
      // In a real application, you would send the edited data to the backend
      // For now, we'll update it locally in the stats object
      const updatedHistory = stats.scan_history.map(scan => {
        if (new Date(scan.timestamp).getTime() === new Date(selectedScan.timestamp).getTime()) {
          return editedScan;
        }
        return scan;
      });

      const updatedStats = {
        ...stats,
        scan_history: updatedHistory
      };

      setStats(updatedStats);
      setSelectedScan(editedScan);
      setEditMode(false);
      setEditedScan(null);

      setSnackbarMessage('Scan details updated successfully');
      setSnackbarOpen(true);
    } catch (error) {
      setSnackbarMessage('Error updating scan details: ' + error.message);
      setSnackbarOpen(true);
    }
  };

  const handleEditFieldChange = (field, value) => {
    setEditedScan(prev => {
      if (field.includes('.')) {
        // Handle nested fields like 'extracted_info.full_name'
        const [parent, child] = field.split('.');
        return {
          ...prev,
          [parent]: {
            ...prev[parent],
            [child]: value
          }
        };
      }
      return {
        ...prev,
        [field]: value
      };
    });
  };

  const handlePrintScan = () => {
    const printWindow = window.open('', '_blank');

    if (!printWindow) {
      setSnackbarMessage('Pop-up blocked. Please allow pop-ups for printing.');
      setSnackbarOpen(true);
      return;
    }

    const scanData = selectedScan;

    printWindow.document.write(`
      <!DOCTYPE html>
      <html>
        <head>
          <title>Scan Details - ${scanData.document_type}</title>
          <style>
            body { font-family: Arial, sans-serif; margin: 20px; }
            .header { text-align: center; margin-bottom: 20px; }
            .section { margin-bottom: 20px; }
            .section-title { font-weight: bold; border-bottom: 1px solid #ccc; padding-bottom: 5px; margin-bottom: 10px; }
            .field { margin-bottom: 10px; }
            .field-name { font-weight: bold; }
            .field-value { margin-left: 10px; }
            .footer { margin-top: 30px; text-align: center; font-size: 0.8em; color: #666; }
          </style>
        </head>
        <body>
          <div class="header">
            <h1>Document Scan Details</h1>
            <p>Scanned on: ${new Date(scanData.timestamp).toLocaleString()}</p>
          </div>

          <div class="section">
            <h2 class="section-title">Document Information</h2>
            <div class="field">
              <span class="field-name">Document Type:</span>
              <span class="field-value">${scanData.document_type?.charAt(0).toUpperCase() + scanData.document_type?.slice(1).replace('_', ' ')}</span>
            </div>
            <div class="field">
              <span class="field-name">Nationality:</span>
              <span class="field-value">${scanData.nationality || 'Unknown'}</span>
            </div>
          </div>

          <div class="section">
            <h2 class="section-title">Extracted Information</h2>
            ${scanData.extracted_info?.full_name ? `
              <div class="field">
                <span class="field-name">Full Name:</span>
                <span class="field-value">${scanData.extracted_info.full_name}</span>
              </div>
            ` : ''}
            ${scanData.extracted_info?.document_number ? `
              <div class="field">
                <span class="field-name">Document Number:</span>
                <span class="field-value">${scanData.extracted_info.document_number}</span>
              </div>
            ` : ''}
            ${scanData.extracted_info?.birth_date ? `
              <div class="field">
                <span class="field-name">Date of Birth:</span>
                <span class="field-value">${scanData.extracted_info.birth_date}</span>
              </div>
            ` : ''}
            ${scanData.extracted_info?.expiry_date ? `
              <div class="field">
                <span class="field-name">Expiry Date:</span>
                <span class="field-value">${scanData.extracted_info.expiry_date}</span>
              </div>
            ` : ''}
            ${scanData.extracted_info?.gender ? `
              <div class="field">
                <span class="field-name">Gender:</span>
                <span class="field-value">${scanData.extracted_info.gender}</span>
              </div>
            ` : ''}
          </div>

          ${scanData.extracted_text ? `
            <div class="section">
              <h2 class="section-title">Raw Extracted Text</h2>
              <pre style="white-space: pre-wrap; background: #f5f5f5; padding: 10px; border-radius: 5px;">${scanData.extracted_text}</pre>
            </div>
          ` : ''}

          <div class="footer">
            <p>Generated by OCR Document Scanner on ${new Date().toLocaleString()}</p>
          </div>
        </body>
      </html>
    `);

    printWindow.document.close();
    setTimeout(() => {
      printWindow.print();
    }, 500);

    setSnackbarMessage('Print preview opened');
    setSnackbarOpen(true);
  };

  const handleExportJSON = () => {
    const dataStr = JSON.stringify(selectedScan, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);

    const exportFileDefaultName = `scan_${selectedScan.document_type}_${new Date(selectedScan.timestamp).toISOString().split('T')[0]}.json`;

    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();

    setSnackbarMessage('Exported scan details as JSON');
    setSnackbarOpen(true);
  };

  const handleMenuOpen = (event) => {
    setMenuAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setMenuAnchorEl(null);
  };

  const handleCopyToClipboard = () => {
    const textToCopy = JSON.stringify(selectedScan, null, 2);
    navigator.clipboard.writeText(textToCopy)
      .then(() => {
        setSnackbarMessage('Copied scan details to clipboard');
        setSnackbarOpen(true);
        handleMenuClose();
      })
      .catch(err => {
        setSnackbarMessage('Failed to copy: ' + err);
        setSnackbarOpen(true);
        handleMenuClose();
      });
  };

  useEffect(() => {
    fetchStats();
  }, []);

  // Prepare chart data for document types
  const documentTypeChartData = {
    labels: stats?.document_types ? Object.keys(stats.document_types).map(type => type.charAt(0).toUpperCase() + type.slice(1)) : [],
    datasets: [
      {
        label: 'Document Types',
        data: stats?.document_types ? Object.values(stats.document_types) : [],
        backgroundColor: [
          'rgba(54, 162, 235, 0.6)',
          'rgba(255, 99, 132, 0.6)',
          'rgba(255, 206, 86, 0.6)',
        ],
        borderColor: [
          'rgba(54, 162, 235, 1)',
          'rgba(255, 99, 132, 1)',
          'rgba(255, 206, 86, 1)',
        ],
        borderWidth: 1,
      },
    ],
  };

  // Prepare chart data for nationalities
  const nationalitiesChartData = {
    labels: stats?.nationalities ? Object.keys(stats.nationalities) : [],
    datasets: [
      {
        label: 'Nationalities',
        data: stats?.nationalities ? Object.values(stats.nationalities) : [],
        backgroundColor: [
          'rgba(75, 192, 192, 0.6)',
          'rgba(153, 102, 255, 0.6)',
          'rgba(255, 159, 64, 0.6)',
          'rgba(255, 99, 132, 0.6)',
          'rgba(54, 162, 235, 0.6)',
          'rgba(255, 206, 86, 0.6)',
        ],
        borderColor: [
          'rgba(75, 192, 192, 1)',
          'rgba(153, 102, 255, 1)',
          'rgba(255, 159, 64, 1)',
          'rgba(255, 99, 132, 1)',
          'rgba(54, 162, 235, 1)',
          'rgba(255, 206, 86, 1)',
        ],
        borderWidth: 1,
      },
    ],
  };

  return (
    <Box sx={{ overflow: 'hidden' }}>
    <Container maxWidth="lg" sx={{ mt: { xs: 2, sm: 3, md: 4 }, mb: { xs: 2, sm: 3, md: 4 }, px: { xs: 1, sm: 2, md: 3 } }}>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
        <Box>
          <Typography variant="h4" component="div" sx={{ display: 'flex', alignItems: 'center', fontSize: { xs: '1.5rem', sm: '1.75rem', md: '2rem' } }}>
            <DescriptionIcon sx={{ mr: 1, fontSize: { xs: 24, sm: 28, md: 32 } }} /> 
            Document Scanner Dashboard
          </Typography>
          <Typography variant="subtitle1" color="text.secondary">
            Monitor document scanning statistics and history
          </Typography>
        </Box>
        <Box>
          <Tooltip title="Refresh statistics">
            <Button 
              variant="contained" 
              startIcon={<RefreshIcon />} 
              onClick={fetchStats}
              size="medium"
              sx={{ mr: { xs: 1, sm: 2 }, px: { xs: 2, sm: 3 } }}
            >
              Refresh
            </Button>
          </Tooltip>
          <Tooltip title="Reset all statistics data">
            <Button 
              variant="outlined" 
              color="error" 
              startIcon={<DeleteIcon />} 
              onClick={resetStats}
              size="medium"
              sx={{ px: { xs: 2, sm: 3 } }}
            >
              Reset Stats
            </Button>
          </Tooltip>
        </Box>
      </Box>

      {error && (
        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
          {error}
        </Alert>
      )}

      {loading ? (
        <Box sx={{ width: '100%' }}>
          <Grid container spacing={{ xs: 2, sm: 3, md: 4 }}>
            {[1, 2, 3, 4].map((item) => (
              <Grid item xs={12} md={3} key={item}>
                <Skeleton variant="rectangular" height={120} animation="wave" />
              </Grid>
            ))}
            {[1, 2].map((item) => (
              <Grid item xs={12} md={6} key={`chart-${item}`}>
                <Skeleton variant="rectangular" height={300} animation="wave" />
              </Grid>
            ))}
            <Grid item xs={12}>
              <Skeleton variant="rectangular" height={400} animation="wave" />
            </Grid>
          </Grid>
        </Box>
      ) : stats ? (
        <Grid container spacing={{ xs: 2, sm: 3, md: 4 }}>
          {/* Summary Cards */}
          <Grid item xs={12} sm={6} md={3}>
            <Paper sx={{ p: { xs: 2, sm: 3 }, display: 'flex', flexDirection: 'column', height: { xs: 130, sm: 150, md: 160 }, position: 'relative', overflow: 'hidden' }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <Typography variant="h6" color="primary" gutterBottom sx={{ fontSize: { xs: '1rem', sm: '1.1rem', md: '1.25rem' } }}>
                  Total Scanned
                </Typography>
                <DescriptionIcon color="primary" sx={{ fontSize: { xs: 32, sm: 36, md: 40 }, opacity: 0.2 }} />
              </Box>
              <Typography variant="h3" component="div" sx={{ mt: 2, fontWeight: 'bold', fontSize: { xs: '1.8rem', sm: '2rem', md: '2.5rem' } }}>
                {stats?.total_scanned || 0}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Documents processed
              </Typography>
              <Box sx={{ 
                position: 'absolute', 
                bottom: 0, 
                left: 0, 
                right: 0, 
                height: '4px', 
                bgcolor: 'primary.main' 
              }} />
            </Paper>
          </Grid>
          <Grid item xs={12} sm={6} md={3}>
            <Paper sx={{ p: { xs: 2, sm: 3 }, display: 'flex', flexDirection: 'column', height: { xs: 130, sm: 150, md: 160 }, position: 'relative', overflow: 'hidden' }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <Typography variant="h6" color="info.main" gutterBottom sx={{ fontSize: { xs: '1rem', sm: '1.1rem', md: '1.25rem' } }}>
                  Passports
                </Typography>
                <PassportIcon color="info" sx={{ fontSize: { xs: 32, sm: 36, md: 40 }, opacity: 0.2 }} />
              </Box>
              <Typography variant="h3" component="div" sx={{ mt: 2, fontWeight: 'bold', fontSize: { xs: '1.8rem', sm: '2rem', md: '2.5rem' } }}>
                {stats?.document_types?.passport || 0}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                {((stats?.document_types?.passport || 0) / (stats?.total_scanned || 1) * 100).toFixed(1)}% of total
              </Typography>
              <Box sx={{ 
                position: 'absolute', 
                bottom: 0, 
                left: 0, 
                right: 0, 
                height: '4px', 
                bgcolor: 'info.main' 
              }} />
            </Paper>
          </Grid>
          <Grid item xs={12} sm={6} md={3}>
            <Paper sx={{ p: { xs: 2, sm: 3 }, display: 'flex', flexDirection: 'column', height: { xs: 130, sm: 150, md: 160 }, position: 'relative', overflow: 'hidden' }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <Typography variant="h6" color="success.main" gutterBottom sx={{ fontSize: { xs: '1rem', sm: '1.1rem', md: '1.25rem' } }}>
                  ID Cards
                </Typography>
                <BadgeIcon color="success" sx={{ fontSize: { xs: 32, sm: 36, md: 40 }, opacity: 0.2 }} />
              </Box>
              <Typography variant="h3" component="div" sx={{ mt: 2, fontWeight: 'bold', fontSize: { xs: '1.8rem', sm: '2rem', md: '2.5rem' } }}>
                {stats?.document_types?.id_card || 0}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                {((stats?.document_types?.id_card || 0) / (stats?.total_scanned || 1) * 100).toFixed(1)}% of total
              </Typography>
              <Box sx={{ 
                position: 'absolute', 
                bottom: 0, 
                left: 0, 
                right: 0, 
                height: '4px', 
                bgcolor: 'success.main' 
              }} />
            </Paper>
          </Grid>
          <Grid item xs={12} sm={6} md={3}>
            <Paper sx={{ p: { xs: 2, sm: 3 }, display: 'flex', flexDirection: 'column', height: { xs: 130, sm: 150, md: 160 }, position: 'relative', overflow: 'hidden' }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <Typography variant="h6" color="warning.main" gutterBottom sx={{ fontSize: { xs: '1rem', sm: '1.1rem', md: '1.25rem' } }}>
                  Countries
                </Typography>
                <PublicIcon color="warning" sx={{ fontSize: { xs: 32, sm: 36, md: 40 }, opacity: 0.2 }} />
              </Box>
              <Typography variant="h3" component="div" sx={{ mt: 2, fontWeight: 'bold', fontSize: { xs: '1.8rem', sm: '2rem', md: '2.5rem' } }}>
                {stats?.nationalities ? Object.keys(stats.nationalities).length : 0}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Unique nationalities
              </Typography>
              <Box sx={{ 
                position: 'absolute', 
                bottom: 0, 
                left: 0, 
                right: 0, 
                height: '4px', 
                bgcolor: 'warning.main' 
              }} />
            </Paper>
          </Grid>

          {/* Charts */}
          <Grid item xs={12} sm={6} md={6}>
            <Paper sx={{ 
              p: { xs: 2, sm: 2.5, md: 3 }, 
              display: 'flex', 
              flexDirection: 'column', 
              height: { xs: 300, sm: 350, md: 380 },
              position: 'relative',
              overflow: 'hidden'
            }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1 }}>
                <Typography variant="h6" color="primary" sx={{ fontSize: { xs: '1rem', sm: '1.1rem', md: '1.25rem' } }}>
                  Document Types
                </Typography>
                <Chip 
                  label={`${stats?.document_types ? Object.keys(stats.document_types).length : 0} types`} 
                  size="small" 
                  color="primary" 
                  variant="outlined"
                />
              </Box>
              <Divider sx={{ mb: 2 }} />
              <Box sx={{ flexGrow: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                {stats?.total_scanned > 0 ? (
                  <Pie 
                    data={documentTypeChartData} 
                    options={{ 
                      maintainAspectRatio: false,
                      plugins: {
                        legend: {
                          position: window.innerWidth < 600 ? 'top' : 'bottom',
                          labels: {
                            boxWidth: window.innerWidth < 600 ? 10 : 15,
                            padding: window.innerWidth < 600 ? 10 : 15,
                            font: {
                              size: window.innerWidth < 600 ? 10 : 12
                            }
                          }
                        },
                        tooltip: {
                          callbacks: {
                            label: function(context) {
                              if (stats && stats.total_scanned) {
                                const label = context.label || '';
                                const value = context.raw || 0;
                                const percentage = ((value / stats.total_scanned) * 100).toFixed(1);
                                return `${label}: ${value} (${percentage}%)`;
                              }
                              return '';
                            }
                          }
                        }
                      }
                    }} 
                  />
                ) : (
                  <Box sx={{ textAlign: 'center', py: 5 }}>
                    <DescriptionIcon sx={{ fontSize: 60, color: 'text.disabled', mb: 2 }} />
                    <Typography variant="body1" color="text.secondary">
                      No documents scanned yet
                    </Typography>
                  </Box>
                )}
              </Box>
            </Paper>
          </Grid>
          <Grid item xs={12} sm={6} md={6}>
            <Paper sx={{ 
              p: { xs: 2, sm: 2.5, md: 3 }, 
              display: 'flex', 
              flexDirection: 'column', 
              height: { xs: 300, sm: 350, md: 380 },
              position: 'relative',
              overflow: 'hidden'
            }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1 }}>
                <Typography variant="h6" color="info.main" sx={{ fontSize: { xs: '1rem', sm: '1.1rem', md: '1.25rem' } }}>
                  Nationalities
                </Typography>
                <Tooltip title="Number of unique countries detected">
                  <Chip 
                    label={`${stats?.nationalities ? Object.keys(stats.nationalities).length : 0} countries`} 
                    size="small" 
                    color="info" 
                    variant="outlined"
                    icon={<PublicIcon sx={{ fontSize: { xs: '0.7rem', sm: '0.8rem' } }} />}
                    sx={{ height: { xs: 24, sm: 28, md: 32 }, '& .MuiChip-label': { fontSize: { xs: '0.7rem', sm: '0.75rem', md: '0.8rem' } } }}
                  />
                </Tooltip>
              </Box>
              <Divider sx={{ mb: 2 }} />
              <Box sx={{ flexGrow: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                {stats?.nationalities && Object.keys(stats.nationalities).length > 0 ? (
                  <Bar 
                    data={nationalitiesChartData} 
                    options={{ 
                      maintainAspectRatio: false,
                      scales: {
                        y: {
                          beginAtZero: true,
                          ticks: {
                            precision: 0
                          }
                        }
                      },
                      plugins: {
                        legend: {
                          display: false
                        },
                        tooltip: {
                          callbacks: {
                            label: (context) => {
                              if (stats && stats.total_scanned) {
                                const label = context.dataset.label || '';
                                const value = context.raw || 0;
                                const percentage = ((value / stats.total_scanned) * 100).toFixed(1);
                                return `${label}: ${value} documents (${percentage}%)`;
                              }
                              return '';
                            }
                          }
                        }
                      }
                    }} 
                  />
                ) : (
                  <Box sx={{ textAlign: 'center', py: 5 }}>
                    <PublicIcon sx={{ fontSize: 60, color: 'text.disabled', mb: 2 }} />
                    <Typography variant="body1" color="text.secondary">
                      No nationality data available
                    </Typography>
                  </Box>
                )}
              </Box>
            </Paper>
          </Grid>

          {/* Scan History */}
          <Grid item xs={12}>
            <Paper sx={{ p: { xs: 2, sm: 2.5, md: 3 } }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
                <Box>
                  <Typography variant="h6" color="primary" sx={{ fontSize: { xs: '1rem', sm: '1.1rem', md: '1.25rem' } }}>
                    Scan History
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    {stats?.scan_history?.length || 0} {(stats?.scan_history?.length || 0) === 1 ? 'entry' : 'entries'} in total
                  </Typography>
                </Box>
                {stats?.scan_history?.length > 0 && (
                  <Tooltip title="Export scan history as CSV">
                    <IconButton 
                      color="primary"
                      size="small"
                      onClick={() => {
                        // Create CSV content
                        const headers = ['Document Type', 'Nationality', 'Timestamp'];
                        const csvContent = [
                          headers.join(','),
                          ...stats.scan_history.map(scan => [
                            scan.document_type,
                            scan.nationality,
                            new Date(scan.timestamp).toLocaleString()
                          ].join(','))
                        ].join('\n');

                        // Create download link
                        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
                        const url = URL.createObjectURL(blob);
                        const link = document.createElement('a');
                        link.setAttribute('href', url);
                        link.setAttribute('download', `scan_history_${new Date().toISOString().split('T')[0]}.csv`);
                        link.style.visibility = 'hidden';
                        document.body.appendChild(link);
                        setTimeout(() => {
                          link.click();
                          document.body.removeChild(link);
                        }, 100);
                      }}
                    >
                      <DownloadIcon />
                    </IconButton>
                  </Tooltip>
                )}
              </Box>
              <Divider sx={{ mb: 2 }} />
              <TableContainer sx={{ maxHeight: 400 }}>
                <Table stickyHeader>
                  <TableHead>
                    <TableRow>
                      <TableCell sx={{ fontWeight: 'bold' }}>#</TableCell>
                      <TableCell sx={{ fontWeight: 'bold' }}>Timestamp</TableCell>
                      <TableCell sx={{ fontWeight: 'bold' }}>Document Type</TableCell>
                      <TableCell sx={{ fontWeight: 'bold' }}>Nationality</TableCell>
                      <TableCell sx={{ fontWeight: 'bold' }}>Actions</TableCell>
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {stats?.scan_history?.length > 0 ? (
                      stats.scan_history.map((scan, index) => (
                        <TableRow 
                          key={index}
                          sx={{
                            '&:nth-of-type(odd)': { backgroundColor: 'rgba(0, 0, 0, 0.02)' },
                            '&:hover': { backgroundColor: 'rgba(0, 0, 0, 0.04)' },
                          }}
                        >
                          <TableCell>{index + 1}</TableCell>
                          <TableCell>
                            {new Date(scan.timestamp).toLocaleString()}
                            {index === 0 && (
                              <Chip 
                                label="Latest" 
                                color="primary" 
                                size="small" 
                                sx={{ ml: 1, height: 20 }} 
                              />
                            )}
                          </TableCell>
                          <TableCell>
                            <Box sx={{ display: 'flex', alignItems: 'center' }}>
                              {scan.document_type === 'passport' ? (
                                <PassportIcon fontSize="small" sx={{ mr: 1, color: 'info.main' }} />
                              ) : scan.document_type === 'id_card' ? (
                                <BadgeIcon fontSize="small" sx={{ mr: 1, color: 'success.main' }} />
                              ) : (
                                <DescriptionIcon fontSize="small" sx={{ mr: 1, color: 'warning.main' }} />
                              )}
                              {scan.document_type.charAt(0).toUpperCase() + scan.document_type.slice(1).replace('_', ' ')}
                            </Box>
                          </TableCell>
                          <TableCell>
                            <Box sx={{ display: 'flex', alignItems: 'center' }}>
                              <PublicIcon fontSize="small" sx={{ mr: 1, color: 'text.secondary' }} />
                              {scan.nationality}
                            </Box>
                          </TableCell>
                          <TableCell>
                            <Tooltip title="View Details">
                              <IconButton 
                                size="small" 
                                color="primary" 
                                onClick={() => handleOpenScanDetails(scan)}
                              >
                                <VisibilityIcon fontSize="small" />
                              </IconButton>
                            </Tooltip>
                          </TableCell>
                        </TableRow>
                      ))
                    ) : (
                      <TableRow>
                        <TableCell colSpan={4} align="center" sx={{ py: 4 }}>
                          <Box sx={{ textAlign: 'center' }}>
                            <DescriptionIcon sx={{ fontSize: 40, color: 'text.disabled', mb: 1 }} />
                            <Typography variant="body1" color="text.secondary">
                              No scan history available
                            </Typography>
                            <Typography variant="body2" color="text.secondary">
                              Use the Scanner page to scan documents
                            </Typography>
                          </Box>
                        </TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>
              </TableContainer>
            </Paper>
          </Grid>
        </Grid>
      ) : (
        <Typography variant="body1">No data available</Typography>
      )}
    </Container>

    {/* Scan Details Dialog */}
    <Dialog 
      open={dialogOpen} 
      onClose={handleCloseScanDetails}
      maxWidth="md"
      fullWidth
    >
      <DialogTitle sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', pb: 1 }}>
        <Box sx={{ display: 'flex', alignItems: 'center' }}>
          {selectedScan?.document_type === 'passport' ? (
            <PassportIcon sx={{ mr: 1, color: 'info.main' }} />
          ) : selectedScan?.document_type === 'id_card' ? (
            <BadgeIcon sx={{ mr: 1, color: 'success.main' }} />
          ) : (
            <DescriptionIcon sx={{ mr: 1, color: 'warning.main' }} />
          )}
          <Typography variant="h6">
            {selectedScan?.document_type?.charAt(0).toUpperCase() + selectedScan?.document_type?.slice(1).replace('_', ' ')} Details
          </Typography>
        </Box>
        <Box>
          {!editMode && (
            <>
              <Tooltip title="Print">
                <IconButton onClick={handlePrintScan} size="small" sx={{ mr: 1 }}>
                  <PrintIcon />
                </IconButton>
              </Tooltip>
              <Tooltip title="More options">
                <IconButton 
                  onClick={handleMenuOpen} 
                  size="small" 
                  sx={{ mr: 1 }}
                  aria-controls={menuOpen ? 'scan-menu' : undefined}
                  aria-haspopup="true"
                  aria-expanded={menuOpen ? 'true' : undefined}
                >
                  <MoreVertIcon />
                </IconButton>
              </Tooltip>
            </>
          )}
          <IconButton onClick={handleCloseScanDetails} size="small">
            <CloseIcon />
          </IconButton>
        </Box>

        {/* Options Menu */}
        <Menu
          id="scan-menu"
          anchorEl={menuAnchorEl}
          open={menuOpen}
          onClose={handleMenuClose}
          MenuListProps={{
            'aria-labelledby': 'more-options-button',
          }}
        >
          <MenuItem onClick={handleEditClick}>
            <EditIcon fontSize="small" sx={{ mr: 1 }} />
            Edit Details
          </MenuItem>
          <MenuItem onClick={handleExportJSON}>
            <FileDownloadIcon fontSize="small" sx={{ mr: 1 }} />
            Export as JSON
          </MenuItem>
          <MenuItem onClick={handleCopyToClipboard}>
            <ContentCopyIcon fontSize="small" sx={{ mr: 1 }} />
            Copy to Clipboard
          </MenuItem>
        </Menu>
      </DialogTitle>

      <Box sx={{ borderBottom: 1, borderColor: 'divider' }}>
        <Tabs value={tabValue} onChange={handleTabChange} aria-label="scan details tabs">
          <Tab label="Details" />
          <Tab label="Raw Text" />
          {selectedScan?.image_data && <Tab label="Image" />}
        </Tabs>
      </Box>
      <DialogContent dividers>
        {selectedScan && (
          <>
            {/* Tab Panel 0: Details */}
            {tabValue === 0 && (
              <Grid container spacing={3}>
                {/* Document Information */}
                <Grid item xs={12} md={6}>
                  <Typography variant="subtitle1" color="primary" gutterBottom>
                    Document Information
                  </Typography>
                  {editMode ? (
                    <Box sx={{ mt: 2 }}>
                      <TextField
                        label="Document Type"
                        value={editedScan.document_type || ''}
                        onChange={(e) => handleEditFieldChange('document_type', e.target.value)}
                        fullWidth
                        margin="dense"
                        size="small"
                        select
                      >
                        <MenuItem value="passport">Passport</MenuItem>
                        <MenuItem value="id_card">ID Card</MenuItem>
                        <MenuItem value="other">Other</MenuItem>
                      </TextField>
                      <TextField
                        label="Nationality"
                        value={editedScan.nationality || ''}
                        onChange={(e) => handleEditFieldChange('nationality', e.target.value)}
                        fullWidth
                        margin="dense"
                        size="small"
                      />
                      <TextField
                        label="Scan Date"
                        value={new Date(editedScan.timestamp).toISOString().split('T')[0]}
                        type="date"
                        fullWidth
                        margin="dense"
                        size="small"
                        InputLabelProps={{ shrink: true }}
                        onChange={(e) => {
                          const newDate = new Date(e.target.value);
                          const currentDate = new Date(editedScan.timestamp);
                          currentDate.setFullYear(newDate.getFullYear());
                          currentDate.setMonth(newDate.getMonth());
                          currentDate.setDate(newDate.getDate());
                          handleEditFieldChange('timestamp', currentDate.toISOString());
                        }}
                      />
                    </Box>
                  ) : (
                    <List dense>
                      <ListItem>
                        <ListItemText 
                          primary="Document Type" 
                          secondary={selectedScan.document_type?.charAt(0).toUpperCase() + selectedScan.document_type?.slice(1).replace('_', ' ')}
                        />
                      </ListItem>
                      <ListItem>
                        <ListItemText 
                          primary="Nationality" 
                          secondary={selectedScan.nationality || 'Unknown'}
                        />
                      </ListItem>
                      <ListItem>
                        <ListItemText 
                          primary="Scan Date" 
                          secondary={new Date(selectedScan.timestamp).toLocaleString()}
                        />
                      </ListItem>
                    </List>
                  )}
                </Grid>

                {/* Extracted Information */}
                <Grid item xs={12} md={6}>
                  <Typography variant="subtitle1" color="primary" gutterBottom>
                    Extracted Information
                  </Typography>
                  {editMode ? (
                    <Box sx={{ mt: 2 }}>
                      <TextField
                        label="Full Name"
                        value={editedScan.extracted_info?.full_name || ''}
                        onChange={(e) => handleEditFieldChange('extracted_info.full_name', e.target.value)}
                        fullWidth
                        margin="dense"
                        size="small"
                      />
                      <TextField
                        label="Document Number"
                        value={editedScan.extracted_info?.document_number || ''}
                        onChange={(e) => handleEditFieldChange('extracted_info.document_number', e.target.value)}
                        fullWidth
                        margin="dense"
                        size="small"
                      />
                      <TextField
                        label="Date of Birth"
                        value={editedScan.extracted_info?.birth_date || ''}
                        onChange={(e) => handleEditFieldChange('extracted_info.birth_date', e.target.value)}
                        fullWidth
                        margin="dense"
                        size="small"
                      />
                      <TextField
                        label="Expiry Date"
                        value={editedScan.extracted_info?.expiry_date || ''}
                        onChange={(e) => handleEditFieldChange('extracted_info.expiry_date', e.target.value)}
                        fullWidth
                        margin="dense"
                        size="small"
                      />
                      <TextField
                        label="Gender"
                        value={editedScan.extracted_info?.gender || ''}
                        onChange={(e) => handleEditFieldChange('extracted_info.gender', e.target.value)}
                        select
                        fullWidth
                        margin="dense"
                        size="small"
                      >
                        <MenuItem value="M">Male</MenuItem>
                        <MenuItem value="F">Female</MenuItem>
                        <MenuItem value="X">Other</MenuItem>
                      </TextField>
                    </Box>
                  ) : (
                    <List dense>
                      {selectedScan.extracted_info?.full_name && (
                        <ListItem>
                          <PersonIcon fontSize="small" sx={{ mr: 1, color: 'text.secondary' }} />
                          <ListItemText 
                            primary="Full Name" 
                            secondary={selectedScan.extracted_info.full_name}
                          />
                        </ListItem>
                      )}
                      {selectedScan.extracted_info?.document_number && (
                        <ListItem>
                          <FingerprintIcon fontSize="small" sx={{ mr: 1, color: 'text.secondary' }} />
                          <ListItemText 
                            primary="Document Number" 
                            secondary={selectedScan.extracted_info.document_number}
                          />
                        </ListItem>
                      )}
                      {selectedScan.extracted_info?.birth_date && (
                        <ListItem>
                          <CalendarTodayIcon fontSize="small" sx={{ mr: 1, color: 'text.secondary' }} />
                          <ListItemText 
                            primary="Date of Birth" 
                            secondary={selectedScan.extracted_info.birth_date}
                          />
                        </ListItem>
                      )}
                      {selectedScan.extracted_info?.expiry_date && (
                        <ListItem>
                          <CalendarTodayIcon fontSize="small" sx={{ mr: 1, color: 'text.secondary' }} />
                          <ListItemText 
                            primary="Expiry Date" 
                            secondary={selectedScan.extracted_info.expiry_date}
                          />
                        </ListItem>
                      )}
                      {selectedScan.extracted_info?.gender && (
                        <ListItem>
                          <PersonIcon fontSize="small" sx={{ mr: 1, color: 'text.secondary' }} />
                          <ListItemText 
                            primary="Gender" 
                            secondary={selectedScan.extracted_info.gender}
                          />
                        </ListItem>
                      )}
                    </List>
                  )}
                </Grid>
              </Grid>
            )}

            {/* Tab Panel 1: Raw Text */}
            {tabValue === 1 && selectedScan.extracted_text && (
              <Box>
                <Typography variant="subtitle1" color="primary" gutterBottom>
                  Raw Extracted Text
                </Typography>
                {editMode ? (
                  <TextField
                    multiline
                    rows={10}
                    value={editedScan.extracted_text || ''}
                    onChange={(e) => handleEditFieldChange('extracted_text', e.target.value)}
                    fullWidth
                    variant="outlined"
                    sx={{ fontFamily: 'monospace', fontSize: '0.85rem' }}
                  />
                ) : (
                  <Paper 
                    variant="outlined" 
                    sx={{ 
                      p: 2, 
                      maxHeight: 400, 
                      overflow: 'auto',
                      bgcolor: 'grey.50',
                      fontFamily: 'monospace',
                      fontSize: '0.85rem'
                    }}
                  >
                    {selectedScan.extracted_text}
                  </Paper>
                )}
              </Box>
            )}

            {/* Tab Panel 2: Image */}
            {tabValue === 2 && selectedScan.image_data && (
              <Box sx={{ textAlign: 'center' }}>
                <Typography variant="subtitle1" color="primary" gutterBottom>
                  Document Image
                </Typography>
                <Box 
                  component="img"
                  src={selectedScan.image_data}
                  alt="Scanned document"
                  sx={{ 
                    maxWidth: '100%', 
                    maxHeight: 500,
                    boxShadow: 1,
                    border: '1px solid #ddd'
                  }}
                />
              </Box>
            )}
          </>
        )}
      </DialogContent>
      <DialogActions>
        {editMode ? (
          <>
            <Button onClick={handleCancelEdit} color="inherit">
              Cancel
            </Button>
            <Button onClick={handleSaveEdit} color="primary" variant="contained">
              Save Changes
            </Button>
          </>
        ) : (
          <Button onClick={handleCloseScanDetails} color="primary">
            Close
          </Button>
        )}
      </DialogActions>
    </Dialog>

    {/* Snackbar for notifications */}
    <Snackbar 
      open={snackbarOpen} 
      autoHideDuration={6000} 
      onClose={() => setSnackbarOpen(false)}
      anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
    >
      <Alert 
        onClose={() => setSnackbarOpen(false)} 
        severity="success" 
        sx={{ width: '100%' }}
      >
        {snackbarMessage}
      </Alert>
    </Snackbar>
    </Box>
  );
};

export default Dashboard;
